const input = $input.first().json;
const rawContent = input[0]?.data || input.data || "";
const CURRENCIES = ["EUR","USD","GBP","JPY","CHF","AUD","NZD","CAD"];
const sourceUrl = 'https://www.forexlive.com/feed/news';

// Dividir por URLs (que empiezan con [https)
const urlPattern = /\[https:\/\/investinglive\.com\/news\/([^\]]+)\]/g;
const matches = [];
let match;
while ((match = urlPattern.exec(rawContent)) !== null) {
  matches.push(match[1]);
}

const news = [];
for (const urlSlug of matches.slice(0, 10)) {
  // Reconstruir headline de la URL (reemplazar guiones por espacios, capitalizar)
  const headline = urlSlug
    .split('-')
    .slice(0, -1)  // remover timestamp
    .join(' ')
    .slice(0, 140);

  if (!headline || headline.length < 10) continue;

  // Buscar moneda en todo el contenido
  const currency = CURRENCIES.find(c => rawContent.toUpperCase().includes(c)) || "";

  // Detectar impact
  const impact = rawContent.toLowerCase().includes("high") ? "high" : 
                 rawContent.toLowerCase().includes("medium") ? "medium" : "low";

  news.push({
    headline: headline.trim(),
    impact,
    currency,
    source_url: sourceUrl,
    content: headline
  });
}

return [{ json: { news } }];

const input = $input.first().json;
const rawContent = input[0]?.data || input.data || "";
const CURRENCIES = ["EUR","USD","GBP","JPY","CHF","AUD","NZD","CAD"];
const sourceUrl = 'https://www.forexfactory.com/calendar';

const lines = rawContent.split('\n');
const tableRows = lines.filter(l => l.includes('|') && !l.includes('---'));

let currentDate = '';
const calendar = [];

for (const row of tableRows) {
  const cells = row.split('|').map(c => c.trim());
  if (cells.length < 5) continue;

  let dateCell = cells[0];
  let timeIdx = 0;
  let currencyIdx = 1;

  if (dateCell.match(/^(Sun|Mon|Tue|Wed|Thu|Fri|Sat)/)) {
    currentDate = dateCell;
    timeIdx = 1;
    currencyIdx = 2;
  } else if (dateCell === '' || !dateCell.match(/:\d{2}/)) {
    for (let i = 1; i < Math.min(4, cells.length); i++) {
      if (CURRENCIES.some(c => cells[i].includes(c))) {
        currencyIdx = i;
        timeIdx = i - 1;
        break;
      }
    }
  }

  let time = cells[timeIdx] || '';
  let currency = '';

  for (let i = currencyIdx; i < Math.min(currencyIdx + 2, cells.length); i++) {
    const found = CURRENCIES.find(c => cells[i].includes(c));
    if (found) {
      currency = found;
      break;
    }
  }

  if (!currency) continue;

  let eventName = '';
  for (let i = currencyIdx + 1; i < cells.length; i++) {
    const cell = cells[i];
    if (cell && !cell.startsWith('!') && !cell.match(/^[0-9%.-]+$/) && cell.length > 5) {
      eventName = cell.slice(0, 120);
      break;
    }
  }

  if (!eventName) continue;

  const impact = row.includes('ff-impact-red') ? 'high' : 
                 row.includes('ff-impact-ora') ? 'high' :
                 row.includes('ff-impact-yel') ? 'medium' : 'low';

  const numCells = cells.filter(c => c && c.match(/^[+-]?[0-9.%K M B]+$/));
  let actual = '';
  let forecast = '';
  let previous = '';
  if (numCells.length >= 3) {
    actual = numCells[0];
    forecast = numCells[1];
    previous = numCells[2];
  } else if (numCells.length === 2) {
    forecast = numCells[0];
    previous = numCells[1];
  } else if (numCells.length === 1) {
    forecast = numCells[0];
  }

  calendar.push({
    event: eventName,
    currency,
    impact,
    time,
    date: currentDate,
    utc_offset: '',
    forecast,
    actual,
    previous,
    source_url: sourceUrl
  });

  if (calendar.length >= 15) break;
}

return [{ json: { calendar } }];

// Triggered by Merge News+Cal (after News+Calendar branches complete).
// GET Prices and GET Positions completed earlier (faster FastAPI calls).
const prices    = $('GET Prices').first().json;
const posData   = $('GET Positions').first().json;
const positions = (posData.open || []).concat(posData.pending || []);
const newsItems = $input.all()
  .filter(i => i.json.news)
  .map(i => i.json.news)
  .flat();
const calItems  = $input.all()
  .filter(i => i.json.calendar)
  .map(i => i.json.calendar)
  .flat();
return [{ json: { prices, positions, news: newsItems, calendar: calItems } }];

